NewInstance = function(instance, parent, properties)
	local inst = Instance.new(instance)
	inst.Parent = parent
	if (properties) then
		for i, v in next, properties do
			pcall(
				function()
					inst[i] = v
				end
			)
		end
	end
	return inst
end
